import"./style-B4IgR0yf.js";const l=document.getElementById("confirmButton"),a=document.getElementById("homeButton"),c=document.getElementById("inventory_count"),r=document.getElementById("product_price"),s=document.getElementById("currentInventory"),m=document.getElementById("currentPrice"),o=document.getElementById("productSelect"),p=localStorage.getItem("adminUsername");function u(){const t=c.value,e=r.value,n=t*e;document.getElementById("total").innerText=`$${n}`}function v(){const t=c.value,e=r.value,n=o.value;fetch("/api/update-inventory",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({product_id:n,inventory:t,price:e,username:p})}).then(i=>i.json()).then(i=>{console.log(i),d()})}function d(){const t=o.value;fetch(`/api/get-inventory/${t}`).then(e=>e.json()).then(e=>{s.innerText=`Current Inventory: ${e.inventory}`,m.innerText=`Current Price: $${e.price}`,c.value=e.inventory,r.value=e.price})}function y(){fetch("/api/get-products").then(t=>t.json()).then(t=>{o.innerHTML="",t.forEach(e=>{const n=document.createElement("option");n.value=e.id,n.textContent=e.name,o.appendChild(n)}),d()})}c.addEventListener("input",u);r.addEventListener("input",u);l.addEventListener("click",()=>{alert("Successfully changed inventory"),v(),console.log("Confirm button clicked")});a.addEventListener("click",()=>{window.location.replace("./adminDashboard.html"),console.log("Home button clicked")});o.addEventListener("change",()=>{d()});y();u();
